class Solution:
    def __init__(self):
        self.buf = []
        self.buf_ptr = 0
    def read(self, n):
        res = []
        while len(res) < n:
            if self.buf_ptr < len(self.buf):
                res.append(self.buf[self.buf_ptr])
                self.buf_ptr += 1
            else:
                tmp = read4()  # provided by framework
                if not tmp: break
                self.buf = tmp
                self.buf_ptr = 0
        return len(res)

